from sklearn.ensemble import GradientBoostingClassifier
from sklearn.metrics import accuracy_score
import numpy as np

def solve(X_train, y_train, X_val, y_val):
    # Initialize the best model and its score
    best_model = None
    best_accuracy = 0

    # Try GradientBoostingClassifier with different parameters
    for learning_rate in [0.1, 0.2]:
        for n_estimators in [50, 100]:
            for max_depth in [3, 4]:
                model = GradientBoostingClassifier(learning_rate=learning_rate, n_estimators=n_estimators, max_depth=max_depth)
                model.fit(X_train, y_train)
                predictions = model.predict(X_val)
                accuracy = accuracy_score(y_val, predictions)

                if accuracy > best_accuracy:
                    best_accuracy = accuracy
                    best_model = model

    # Return the predictions of the best model found
    return best_model.predict(X_val)

from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score
import numpy as np

def solve(X_train, y_train, X_val, y_val):
    # Try a different number of trees and max depth to potentially improve the model
    best_accuracy = 0
    for n_estimators in [100, 200]:
        for max_depth in [None, 10, 20]:
            clf = RandomForestClassifier(n_estimators=n_estimators, max_depth=max_depth, random_state=42)
            clf.fit(X_train, y_train)
            predictions = clf.predict(X_val)
            accuracy = accuracy_score(y_val, predictions)
            if accuracy > best_accuracy:
                best_accuracy = accuracy
    return np.array(best_accuracy)
